mapper.select:
SELECT id, meeting_id, section_type, sort_order, content, work_request_no
  FROM hkgn.daily_meeting_note
 WHERE id = #{id}

mapper.insert:
INSERT INTO hkgn.daily_meeting_note (
    meeting_id, section_type, sort_order, content, work_request_no
) VALUES (
    #{meetingId}, #{sectionType}, #{sortOrder}, #{content}, #{workRequestNo}
)

mapper.select:
SELECT COALESCE(MAX(sort_order), 0)
  FROM hkgn.daily_meeting_note
 WHERE meeting_id = #{meetingId}
